  39: { 'id': 39, 'height': 5, 'weight': 55, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/39.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/39.png', 'abilities': ['Cute Charm', 'Competitive', 'Friend Guard'], 'stats': { 'hp': 115, 'attack': 45, 'defense': 20, 'special-attack': 45, 'special-defense': 25, 'speed': 20 }, 'flavorText': 'When its huge eyes light up, it sings a mysteriously soothing melody that lulls its enemies to sleep.', 'evolutionChains': [[{ 'id': 174, 'name': 'Igglybuff' }, { 'id': 39, 'name': 'Jigglypuff', 'condition': 'Friendship 160' }, { 'id': 40, 'name': 'Wigglytuff', 'condition': 'Use Moon Stone' }]] },
