  48: { 'id': 48, 'height': 10, 'weight': 300, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/48.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/48.png', 'abilities': ['Compound Eyes', 'Tinted Lens', 'Run Away'], 'stats': { 'hp': 60, 'attack': 55, 'defense': 50, 'special-attack': 40, 'special-defense': 55, 'speed': 45 }, 'flavorText': 'Its big eyes are actually clusters of tiny eyes. At night, its kind is drawn by light.', 'evolutionChains': [[{ 'id': 48, 'name': 'Venonat' }, { 'id': 49, 'name': 'Venomoth', 'condition': 'Lv. 31' }]] },
