  158: { 'id': 158, 'height': 6, 'weight': 95, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/158.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/158.png', 'abilities': ['Torrent', 'Sheer Force'], 'stats': { 'hp': 50, 'attack': 65, 'defense': 64, 'special-attack': 44, 'special-defense': 48, 'speed': 43 }, 'flavorText': 'Its well-developed jaws are powerful and capable of crushing anything. Even its trainer must be careful.', 'evolutionChains': [[{ 'id': 158, 'name': 'Totodile' }, { 'id': 159, 'name': 'Croconaw', 'condition': 'Lv. 18' }, { 'id': 160, 'name': 'Feraligatr', 'condition': 'Lv. 30' }]] },
