  206: { 'id': 206, 'height': 15, 'weight': 140, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/206.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/206.png', 'abilities': ['Serene Grace', 'Run Away', 'Rattled'], 'stats': { 'hp': 100, 'attack': 70, 'defense': 70, 'special-attack': 65, 'special-defense': 65, 'speed': 45 }, 'flavorText': 'When spotted, this POKéMON escapes backward by furi­ ously boring into the ground with its tail.', 'evolutionChains': [[{ 'id': 206, 'name': 'Dunsparce' }, { 'id': 982, 'name': 'Dudunsparce', 'condition': 'Know Hyper Drill' }]] },
