  210: { 'id': 210, 'height': 14, 'weight': 487, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/210.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/210.png', 'abilities': ['Intimidate', 'Quick Feet', 'Rattled'], 'stats': { 'hp': 90, 'attack': 120, 'defense': 75, 'special-attack': 60, 'special-defense': 60, 'speed': 45 }, 'flavorText': 'It is actually timid and easily spooked. If at­ tacked, it flails about to fend off its attacker.', 'evolutionChains': [[{ 'id': 209, 'name': 'Snubbull' }, { 'id': 210, 'name': 'Granbull', 'condition': 'Lv. 23' }]] },
