  218: { 'id': 218, 'height': 7, 'weight': 350, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/218.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/218.png', 'abilities': ['Magma Armor', 'Flame Body', 'Weak Armor'], 'stats': { 'hp': 40, 'attack': 40, 'defense': 40, 'special-attack': 70, 'special-defense': 40, 'speed': 20 }, 'flavorText': 'Its body is made of magma. If it doesn’t keep moving, its body will cool and harden.', 'evolutionChains': [[{ 'id': 218, 'name': 'Slugma' }, { 'id': 219, 'name': 'Magcargo', 'condition': 'Lv. 38' }]] },
  219: { 'id': 219, 'height': 8, 'weight': 550, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/219.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/219.png', 'abilities': ['Magma Armor', 'Flame Body', 'Weak Armor'], 'stats': { 'hp': 60, 'attack': 50, 'defense': 120, 'special-attack': 90, 'special-defense': 80, 'speed': 30 }, 'flavorText': 'The shell on its back is just skin that has cooled and hardened. It breaks easily with a slight touch.', 'evolutionChains': [[{ 'id': 218, 'name': 'Slugma' }, { 'id': 219, 'name': 'Magcargo', 'condition': 'Lv. 38' }]] },
  220: { 'id': 220, 'height': 4, 'weight': 65, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/220.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/220.png', 'abilities': ['Oblivious', 'Snow Cloak', 'Thick Fat'], 'stats': { 'hp': 50, 'attack': 50, 'defense': 40, 'special-attack': 30, 'special-defense': 30, 'speed': 50 }, 'flavorText': 'It rubs its snout on the ground to find and dig up food. It sometimes discovers hot springs.', 'evolutionChains': [[{ 'id': 220, 'name': 'Swinub' }, { 'id': 221, 'name': 'Piloswine', 'condition': 'Lv. 33' }, { 'id': 473, 'name': 'Mamoswine', 'condition': 'Know Ancient Power' }]] },
  221: { 'id': 221, 'height': 11, 'weight': 558, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/221.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/221.png', 'abilities': ['Oblivious', 'Snow Cloak', 'Thick Fat'], 'stats': { 'hp': 100, 'attack': 100, 'defense': 80, 'special-attack': 60, 'special-defense': 60, 'speed': 50 }, 'flavorText': 'Although its legs are short, its rugged hooves prevent it from slipping, even on icy ground.', 'evolutionChains': [[{ 'id': 220, 'name': 'Swinub' }, { 'id': 221, 'name': 'Piloswine', 'condition': 'Lv. 33' }, { 'id': 473, 'name': 'Mamoswine', 'condition': 'Know Ancient Power' }]] },
  222: { 'id': 222, 'height': 6, 'weight': 50, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/222.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/222.png', 'abilities': ['Hustle', 'Natural Cure', 'Regenerator'], 'stats': { 'hp': 65, 'attack': 55, 'defense': 95, 'special-attack': 65, 'special-defense': 95, 'speed': 35 }, 'flavorText': 'It continuously sheds and grows. The tip of its head is prized as a treasure for its beauty.', 'evolutionChains': [[{ 'id': 222, 'name': 'Corsola' }, { 'id': 864, 'name': 'Cursola', 'condition': 'Lv. 38' }]] },
