  226: { 'id': 226, 'height': 21, 'weight': 2200, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/226.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/226.png', 'abilities': ['Swift Swim', 'Water Absorb', 'Water Veil'], 'stats': { 'hp': 85, 'attack': 40, 'defense': 70, 'special-attack': 80, 'special-defense': 140, 'speed': 70 }, 'flavorText': 'As it majestically swims, it doesn\'t care if REMORAID attach to it for scavenging its leftovers.', 'evolutionChains': [[{ 'id': 458, 'name': 'Mantyke' }, { 'id': 226, 'name': 'Mantine', 'condition': 'With Remoraid' }]] },
