  236: { 'id': 236, 'height': 7, 'weight': 210, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/236.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/236.png', 'abilities': ['Guts', 'Steadfast', 'Vital Spirit'], 'stats': { 'hp': 35, 'attack': 35, 'defense': 35, 'special-attack': 35, 'special-defense': 35, 'speed': 35 }, 'flavorText': 'It is always bursting with en­ ergy. To make it­ self stronger, it keeps on fighting even if it loses.', 'evolutionChains': [[{ 'id': 236, 'name': 'Tyrogue' }, { 'id': 106, 'name': 'Hitmonlee', 'condition': 'Lv. 20 + Attack > Defense' }], [{ 'id': 236, 'name': 'Tyrogue' }, { 'id': 107, 'name': 'Hitmonchan', 'condition': 'Lv. 20 + Attack < Defense' }], [{ 'id': 236, 'name': 'Tyrogue' }, { 'id': 237, 'name': 'Hitmontop', 'condition': 'Lv. 20 + Attack = Defense' }]] },
  237: { 'id': 237, 'height': 14, 'weight': 480, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/237.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/237.png', 'abilities': ['Intimidate', 'Technician', 'Steadfast'], 'stats': { 'hp': 50, 'attack': 95, 'defense': 95, 'special-attack': 35, 'special-defense': 110, 'speed': 70 }, 'flavorText': 'If you become enchanted by its smooth, elegant, dance-like kicks, you may get drilled hard.', 'evolutionChains': [[{ 'id': 236, 'name': 'Tyrogue' }, { 'id': 106, 'name': 'Hitmonlee', 'condition': 'Lv. 20 + Attack > Defense' }], [{ 'id': 236, 'name': 'Tyrogue' }, { 'id': 107, 'name': 'Hitmonchan', 'condition': 'Lv. 20 + Attack < Defense' }], [{ 'id': 236, 'name': 'Tyrogue' }, { 'id': 237, 'name': 'Hitmontop', 'condition': 'Lv. 20 + Attack = Defense' }]] },
  238: { 'id': 238, 'height': 4, 'weight': 60, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/238.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/238.png', 'abilities': ['Oblivious', 'Forewarn', 'Hydration'], 'stats': { 'hp': 45, 'attack': 30, 'defense': 15, 'special-attack': 85, 'special-defense': 65, 'speed': 65 }, 'flavorText': 'Its lips are the most sensitive parts on its body. It always uses its lips first to examine things.', 'evolutionChains': [[{ 'id': 238, 'name': 'Smoochum' }, { 'id': 124, 'name': 'Jynx', 'condition': 'Lv. 30' }]] },
