  241: { 'id': 241, 'height': 12, 'weight': 755, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/241.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/241.png', 'abilities': ['Thick Fat', 'Scrappy', 'Sap Sipper'], 'stats': { 'hp': 95, 'attack': 80, 'defense': 105, 'special-attack': 40, 'special-defense': 70, 'speed': 100 }, 'flavorText': 'Its milk is packed with nutrition, making it the ultimate beverage for the sick or weary.', 'evolutionChains': [[{ 'id': 241, 'name': 'Miltank' }]] },
  242: { 'id': 242, 'height': 15, 'weight': 468, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/242.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/242.png', 'abilities': ['Natural Cure', 'Serene Grace', 'Healer'], 'stats': { 'hp': 255, 'attack': 10, 'defense': 10, 'special-attack': 75, 'special-defense': 135, 'speed': 55 }, 'flavorText': 'Anyone who takes even one bite of BLISSEY\'s egg be­ comes unfailingly caring and pleas­ ant to everyone.', 'evolutionChains': [[{ 'id': 440, 'name': 'Happiny' }, { 'id': 113, 'name': 'Chansey', 'condition': 'Hold Oval Stone + Day' }, { 'id': 242, 'name': 'Blissey', 'condition': 'Friendship 160' }]] },
