  244: { 'id': 244, 'height': 21, 'weight': 1980, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/244.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/244.png', 'abilities': ['Pressure', 'Inner Focus'], 'stats': { 'hp': 115, 'attack': 115, 'defense': 85, 'special-attack': 90, 'special-defense': 75, 'speed': 100 }, 'flavorText': 'Volcanoes erupt when it barks. Un­ able to restrain its extreme power, it races headlong around the land.', 'evolutionChains': [[{ 'id': 244, 'name': 'Entei' }]] },
