  246: { 'id': 246, 'height': 6, 'weight': 720, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/246.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/246.png', 'abilities': ['Guts', 'Sand Veil'], 'stats': { 'hp': 50, 'attack': 64, 'defense': 50, 'special-attack': 45, 'special-defense': 50, 'speed': 41 }, 'flavorText': 'It feeds on soil. After it has eaten a large mountain, it will fall asleep so it can grow.', 'evolutionChains': [[{ 'id': 246, 'name': 'Larvitar' }, { 'id': 247, 'name': 'Pupitar', 'condition': 'Lv. 30' }, { 'id': 248, 'name': 'Tyranitar', 'condition': 'Lv. 55' }]] },
  247: { 'id': 247, 'height': 12, 'weight': 1520, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/247.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/247.png', 'abilities': ['Shed Skin'], 'stats': { 'hp': 70, 'attack': 84, 'defense': 70, 'special-attack': 65, 'special-defense': 70, 'speed': 51 }, 'flavorText': 'Its shell is as hard as sheet rock, and it is also very strong. Its THRASHING can topple a mountain.', 'evolutionChains': [[{ 'id': 246, 'name': 'Larvitar' }, { 'id': 247, 'name': 'Pupitar', 'condition': 'Lv. 30' }, { 'id': 248, 'name': 'Tyranitar', 'condition': 'Lv. 55' }]] },
  248: { 'id': 248, 'height': 20, 'weight': 2020, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/248.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/248.png', 'abilities': ['Sand Stream', 'Unnerve'], 'stats': { 'hp': 100, 'attack': 134, 'defense': 110, 'special-attack': 95, 'special-defense': 100, 'speed': 61 }, 'flavorText': 'Its body can\'t be harmed by any sort of attack, so it is very eager to make challenges against enemies.', 'evolutionChains': [[{ 'id': 246, 'name': 'Larvitar' }, { 'id': 247, 'name': 'Pupitar', 'condition': 'Lv. 30' }, { 'id': 248, 'name': 'Tyranitar', 'condition': 'Lv. 55' }]] },
  249: { 'id': 249, 'height': 52, 'weight': 2160, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/249.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/249.png', 'abilities': ['Pressure', 'Multiscale'], 'stats': { 'hp': 106, 'attack': 90, 'defense': 130, 'special-attack': 90, 'special-defense': 154, 'speed': 110 }, 'flavorText': 'It is said that it quietly spends its time deep at the bottom of the sea because its powers are too strong.', 'evolutionChains': [[{ 'id': 249, 'name': 'Lugia' }]] },
  250: { 'id': 250, 'height': 38, 'weight': 1990, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/250.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/250.png', 'abilities': ['Pressure', 'Regenerator'], 'stats': { 'hp': 106, 'attack': 130, 'defense': 90, 'special-attack': 110, 'special-defense': 154, 'speed': 90 }, 'flavorText': 'Legends claim this POKéMON flies the world\'s skies con­ tinuously on its magnificent seven- colored wings.', 'evolutionChains': [[{ 'id': 250, 'name': 'Ho Oh' }]] },
  251: { 'id': 251, 'height': 6, 'weight': 50, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/251.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/251.png', 'abilities': ['Natural Cure'], 'stats': { 'hp': 100, 'attack': 100, 'defense': 100, 'special-attack': 100, 'special-defense': 100, 'speed': 100 }, 'flavorText': 'This POKéMON wan­ ders across time. Grass and trees flourish in the forests in which it has appeared.', 'evolutionChains': [[{ 'id': 251, 'name': 'Celebi' }]] },
  252: { 'id': 252, 'height': 5, 'weight': 50, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/252.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/252.png', 'abilities': ['Overgrow', 'Unburden'], 'stats': { 'hp': 40, 'attack': 45, 'defense': 35, 'special-attack': 65, 'special-defense': 55, 'speed': 70 }, 'flavorText': 'TREECKO has small hooks on the bottom of its feet that enable it to scale vertical walls. This POKéMON attacks by slamming foes with its thick tail.', 'evolutionChains': [[{ 'id': 252, 'name': 'Treecko' }, { 'id': 253, 'name': 'Grovyle', 'condition': 'Lv. 16' }, { 'id': 254, 'name': 'Sceptile', 'condition': 'Lv. 36' }]] },
