  396: { 'id': 396, 'height': 3, 'weight': 20, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/396.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/396.png', 'abilities': ['Keen Eye', 'Reckless'], 'stats': { 'hp': 40, 'attack': 55, 'defense': 30, 'special-attack': 30, 'special-defense': 30, 'speed': 60 }, 'flavorText': 'They flock in great numbers. Though small, they flap their wings with great power.', 'evolutionChains': [[{ 'id': 396, 'name': 'Starly' }, { 'id': 397, 'name': 'Staravia', 'condition': 'Lv. 14' }, { 'id': 398, 'name': 'Staraptor', 'condition': 'Lv. 34' }]] },
