  421: { 'id': 421, 'height': 5, 'weight': 93, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/421.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/421.png', 'abilities': ['Flower Gift'], 'stats': { 'hp': 70, 'attack': 60, 'defense': 70, 'special-attack': 87, 'special-defense': 78, 'speed': 85 }, 'flavorText': 'It blooms during times of strong sunlight. It tries to make up for everything it endured as a bud.', 'evolutionChains': [[{ 'id': 420, 'name': 'Cherubi' }, { 'id': 421, 'name': 'Cherrim', 'condition': 'Lv. 25' }]] },
