  505: { 'id': 505, 'height': 11, 'weight': 270, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/505.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/505.png', 'abilities': ['Illuminate', 'Keen Eye', 'Analytic'], 'stats': { 'hp': 60, 'attack': 85, 'defense': 69, 'special-attack': 60, 'special-defense': 69, 'speed': 77 }, 'flavorText': 'When they see an enemy, their tails stand high, and they spit the seeds of berries stored in their cheek pouches.', 'evolutionChains': [[{ 'id': 504, 'name': 'Patrat' }, { 'id': 505, 'name': 'Watchog', 'condition': 'Lv. 20' }]] },
  506: { 'id': 506, 'height': 4, 'weight': 41, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/506.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/506.png', 'abilities': ['Vital Spirit', 'Pickup', 'Run Away'], 'stats': { 'hp': 45, 'attack': 60, 'defense': 45, 'special-attack': 25, 'special-defense': 45, 'speed': 55 }, 'flavorText': 'It faces strong opponents with great courage. But, when at a disadvantage in a fight, this intelligent Pokémon flees.', 'evolutionChains': [[{ 'id': 506, 'name': 'Lillipup' }, { 'id': 507, 'name': 'Herdier', 'condition': 'Lv. 16' }, { 'id': 508, 'name': 'Stoutland', 'condition': 'Lv. 32' }]] },
