  508: { 'id': 508, 'height': 12, 'weight': 610, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/508.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/508.png', 'abilities': ['Intimidate', 'Sand Rush', 'Scrappy'], 'stats': { 'hp': 85, 'attack': 110, 'defense': 90, 'special-attack': 45, 'special-defense': 90, 'speed': 80 }, 'flavorText': 'It rescues people stranded by blizzards in the mountains. Its shaggy fur shields it from the cold.', 'evolutionChains': [[{ 'id': 506, 'name': 'Lillipup' }, { 'id': 507, 'name': 'Herdier', 'condition': 'Lv. 16' }, { 'id': 508, 'name': 'Stoutland', 'condition': 'Lv. 32' }]] },
  509: { 'id': 509, 'height': 4, 'weight': 101, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/509.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/509.png', 'abilities': ['Limber', 'Unburden', 'Prankster'], 'stats': { 'hp': 41, 'attack': 50, 'defense': 37, 'special-attack': 50, 'special-defense': 37, 'speed': 66 }, 'flavorText': 'They steal from people for fun, but their victims can’t help but forgive them. Their deceptively cute act is perfect.', 'evolutionChains': [[{ 'id': 509, 'name': 'Purrloin' }, { 'id': 510, 'name': 'Liepard', 'condition': 'Lv. 20' }]] },
  510: { 'id': 510, 'height': 11, 'weight': 375, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/510.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/510.png', 'abilities': ['Limber', 'Unburden', 'Prankster'], 'stats': { 'hp': 64, 'attack': 88, 'defense': 50, 'special-attack': 88, 'special-defense': 50, 'speed': 106 }, 'flavorText': 'These Pokémon vanish and appear unexpectedly. Many Trainers are drawn to their beautiful form and fur.', 'evolutionChains': [[{ 'id': 509, 'name': 'Purrloin' }, { 'id': 510, 'name': 'Liepard', 'condition': 'Lv. 20' }]] },
  511: { 'id': 511, 'height': 6, 'weight': 105, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/511.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/511.png', 'abilities': ['Gluttony', 'Overgrow'], 'stats': { 'hp': 50, 'attack': 53, 'defense': 48, 'special-attack': 53, 'special-defense': 48, 'speed': 64 }, 'flavorText': 'This Pokémon dwells deep in the forest. Eating a leaf from its head whisks weariness away as if by magic.', 'evolutionChains': [[{ 'id': 511, 'name': 'Pansage' }, { 'id': 512, 'name': 'Simisage', 'condition': 'Use Leaf Stone' }]] },
  512: { 'id': 512, 'height': 11, 'weight': 305, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/512.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/512.png', 'abilities': ['Gluttony', 'Overgrow'], 'stats': { 'hp': 75, 'attack': 98, 'defense': 63, 'special-attack': 98, 'special-defense': 63, 'speed': 101 }, 'flavorText': 'Ill tempered, it fights by swinging its barbed tail around wildly. The leaf growing on its head is very bitter.', 'evolutionChains': [[{ 'id': 511, 'name': 'Pansage' }, { 'id': 512, 'name': 'Simisage', 'condition': 'Use Leaf Stone' }]] },
  513: { 'id': 513, 'height': 6, 'weight': 110, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/513.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/513.png', 'abilities': ['Gluttony', 'Blaze'], 'stats': { 'hp': 50, 'attack': 53, 'defense': 48, 'special-attack': 53, 'special-defense': 48, 'speed': 64 }, 'flavorText': 'When it is angered, the temperature of its head tuft reaches 600° F. It uses its tuft to roast berries.', 'evolutionChains': [[{ 'id': 513, 'name': 'Pansear' }, { 'id': 514, 'name': 'Simisear', 'condition': 'Use Fire Stone' }]] },
  514: { 'id': 514, 'height': 10, 'weight': 280, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/514.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/514.png', 'abilities': ['Gluttony', 'Blaze'], 'stats': { 'hp': 75, 'attack': 98, 'defense': 63, 'special-attack': 98, 'special-defense': 63, 'speed': 101 }, 'flavorText': 'It loves sweets because they become energy for the fire burning inside its body.', 'evolutionChains': [[{ 'id': 513, 'name': 'Pansear' }, { 'id': 514, 'name': 'Simisear', 'condition': 'Use Fire Stone' }]] },
  515: { 'id': 515, 'height': 6, 'weight': 135, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/515.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/515.png', 'abilities': ['Gluttony', 'Torrent'], 'stats': { 'hp': 50, 'attack': 53, 'defense': 48, 'special-attack': 53, 'special-defense': 48, 'speed': 64 }, 'flavorText': 'The water stored inside the tuft on its head is full of nutrients. Plants that receive its water grow large.', 'evolutionChains': [[{ 'id': 515, 'name': 'Panpour' }, { 'id': 516, 'name': 'Simipour', 'condition': 'Use Water Stone' }]] },
  516: { 'id': 516, 'height': 10, 'weight': 290, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/516.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/516.png', 'abilities': ['Gluttony', 'Torrent'], 'stats': { 'hp': 75, 'attack': 98, 'defense': 63, 'special-attack': 98, 'special-defense': 63, 'speed': 101 }, 'flavorText': 'The tuft on its head holds water. When the level runs low, it replenishes the tuft by siphoning up water with its tail.', 'evolutionChains': [[{ 'id': 515, 'name': 'Panpour' }, { 'id': 516, 'name': 'Simipour', 'condition': 'Use Water Stone' }]] },
  517: { 'id': 517, 'height': 6, 'weight': 233, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/517.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/517.png', 'abilities': ['Forewarn', 'Synchronize', 'Telepathy'], 'stats': { 'hp': 76, 'attack': 25, 'defense': 45, 'special-attack': 67, 'special-defense': 55, 'speed': 24 }, 'flavorText': 'Munna always float in the air. People whose dreams are eaten by them forget what the dreams had been about.', 'evolutionChains': [[{ 'id': 517, 'name': 'Munna' }, { 'id': 518, 'name': 'Musharna', 'condition': 'Use Moon Stone' }]] },
  518: { 'id': 518, 'height': 11, 'weight': 605, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/518.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/518.png', 'abilities': ['Forewarn', 'Synchronize', 'Telepathy'], 'stats': { 'hp': 116, 'attack': 55, 'defense': 85, 'special-attack': 107, 'special-defense': 95, 'speed': 29 }, 'flavorText': 'The mist emanating from their foreheads is packed with the dreams of people and Pokémon.', 'evolutionChains': [[{ 'id': 517, 'name': 'Munna' }, { 'id': 518, 'name': 'Musharna', 'condition': 'Use Moon Stone' }]] },
  519: { 'id': 519, 'height': 3, 'weight': 21, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/519.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/519.png', 'abilities': ['Big Pecks', 'Super Luck', 'Rivalry'], 'stats': { 'hp': 50, 'attack': 55, 'defense': 50, 'special-attack': 36, 'special-defense': 30, 'speed': 43 }, 'flavorText': 'Each follows its Trainer’s orders as best it can, but they sometimes fail to understand complicated commands.', 'evolutionChains': [[{ 'id': 519, 'name': 'Pidove' }, { 'id': 520, 'name': 'Tranquill', 'condition': 'Lv. 21' }, { 'id': 521, 'name': 'Unfezant', 'condition': 'Lv. 32' }]] },
