  521: { 'id': 521, 'height': 12, 'weight': 290, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/521.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/521.png', 'abilities': ['Big Pecks', 'Super Luck', 'Rivalry'], 'stats': { 'hp': 80, 'attack': 115, 'defense': 80, 'special-attack': 65, 'special-defense': 55, 'speed': 93 }, 'flavorText': 'Males swing their head plumage to threaten opponents. The females’ flying abilities surpass those of the males.', 'evolutionChains': [[{ 'id': 519, 'name': 'Pidove' }, { 'id': 520, 'name': 'Tranquill', 'condition': 'Lv. 21' }, { 'id': 521, 'name': 'Unfezant', 'condition': 'Lv. 32' }]] },
  522: { 'id': 522, 'height': 8, 'weight': 298, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/522.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/522.png', 'abilities': ['Lightning Rod', 'Motor Drive', 'Sap Sipper'], 'stats': { 'hp': 45, 'attack': 60, 'defense': 32, 'special-attack': 50, 'special-defense': 32, 'speed': 76 }, 'flavorText': 'Its mane shines when it discharges electricity. They use their flashing manes to communicate with one another.', 'evolutionChains': [[{ 'id': 522, 'name': 'Blitzle' }, { 'id': 523, 'name': 'Zebstrika', 'condition': 'Lv. 27' }]] },
