  543: { 'id': 543, 'height': 4, 'weight': 53, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/543.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/543.png', 'abilities': ['Poison Point', 'Swarm', 'Speed Boost'], 'stats': { 'hp': 30, 'attack': 45, 'defense': 59, 'special-attack': 30, 'special-defense': 39, 'speed': 57 }, 'flavorText': 'Its bite injects a potent poison, enough to paralyze large bird Pokémon that try to prey on it.', 'evolutionChains': [[{ 'id': 543, 'name': 'Venipede' }, { 'id': 544, 'name': 'Whirlipede', 'condition': 'Lv. 22' }, { 'id': 545, 'name': 'Scolipede', 'condition': 'Lv. 30' }]] },
