  546: { 'id': 546, 'height': 3, 'weight': 6, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/546.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/546.png', 'abilities': ['Prankster', 'Infiltrator', 'Chlorophyll'], 'stats': { 'hp': 40, 'attack': 27, 'defense': 60, 'special-attack': 37, 'special-defense': 50, 'speed': 66 }, 'flavorText': 'When attacked, it escapes by shooting cotton from its body. The cotton serves as a decoy to distract the attacker.', 'evolutionChains': [[{ 'id': 546, 'name': 'Cottonee' }, { 'id': 547, 'name': 'Whimsicott', 'condition': 'Use Sun Stone' }]] },
  547: { 'id': 547, 'height': 7, 'weight': 66, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/547.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/547.png', 'abilities': ['Prankster', 'Infiltrator', 'Chlorophyll'], 'stats': { 'hp': 60, 'attack': 67, 'defense': 85, 'special-attack': 77, 'special-defense': 75, 'speed': 116 }, 'flavorText': 'Like the wind, it can slip through any gap, no matter how small. It leaves balls of white fluff behind.', 'evolutionChains': [[{ 'id': 546, 'name': 'Cottonee' }, { 'id': 547, 'name': 'Whimsicott', 'condition': 'Use Sun Stone' }]] },
