  549: { 'id': 549, 'height': 11, 'weight': 163, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/549.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/549.png', 'abilities': ['Chlorophyll', 'Own Tempo', 'Leaf Guard'], 'stats': { 'hp': 70, 'attack': 60, 'defense': 75, 'special-attack': 110, 'special-defense': 75, 'speed': 90 }, 'flavorText': 'Even veteran Trainers face a challenge in getting its beautiful flower to bloom. This Pokémon is popular with celebrities.', 'evolutionChains': [[{ 'id': 548, 'name': 'Petilil' }, { 'id': 549, 'name': 'Lilligant', 'condition': 'Use Sun Stone' }]] },
