  551: { 'id': 551, 'height': 7, 'weight': 152, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/551.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/551.png', 'abilities': ['Intimidate', 'Moxie', 'Anger Point'], 'stats': { 'hp': 50, 'attack': 72, 'defense': 35, 'special-attack': 35, 'special-defense': 35, 'speed': 65 }, 'flavorText': 'They live buried in the sands of the desert. The sun-warmed sands prevent their body temperature from dropping.', 'evolutionChains': [[{ 'id': 551, 'name': 'Sandile' }, { 'id': 552, 'name': 'Krokorok', 'condition': 'Lv. 29' }, { 'id': 553, 'name': 'Krookodile', 'condition': 'Lv. 40' }]] },
