  985: { 'id': 985, 'height': 12, 'weight': 80, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/985.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/985.png', 'abilities': ['Protosynthesis'], 'stats': { 'hp': 115, 'attack': 65, 'defense': 99, 'special-attack': 65, 'special-defense': 115, 'speed': 111 }, 'flavorText': 'There has been only one reported sighting of this Pokémon. It resembles a mysterious creature depicted in an old expedition journal.', 'evolutionChains': [[{ 'id': 985, 'name': 'Scream Tail' }]] },
