  998: { 'id': 998, 'height': 21, 'weight': 2100, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/998.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/998.png', 'abilities': ['Thermal Exchange', 'Ice Body'], 'stats': { 'hp': 115, 'attack': 145, 'defense': 92, 'special-attack': 75, 'special-defense': 86, 'speed': 87 }, 'flavorText': 'This Pokémon blasts cryogenic air out from its mouth. This air can instantly freeze even liquid-hot lava.', 'evolutionChains': [[{ 'id': 996, 'name': 'Frigibax' }, { 'id': 997, 'name': 'Arctibax', 'condition': 'Lv. 35' }, { 'id': 998, 'name': 'Baxcalibur', 'condition': 'Lv. 54' }]] },
  999: { 'id': 999, 'height': 3, 'weight': 50, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/999.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/999.png', 'abilities': ['Rattled'], 'stats': { 'hp': 45, 'attack': 30, 'defense': 70, 'special-attack': 75, 'special-defense': 70, 'speed': 10 }, 'flavorText': 'This Pokémon was born inside a treasure chest about 1,500 years ago. It sucks the life-force out of scoundrels who try to steal the treasure.', 'evolutionChains': [[{ 'id': 999, 'name': 'Gimmighoul' }, { 'id': 1000, 'name': 'Gholdengo', 'condition': 'Gimmighoul Coins' }]] },
  1000: { 'id': 1000, 'height': 12, 'weight': 300, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/1000.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1000.png', 'abilities': ['Good As Gold'], 'stats': { 'hp': 87, 'attack': 60, 'defense': 95, 'special-attack': 133, 'special-defense': 91, 'speed': 84 }, 'flavorText': 'Its body seems to be made up of 1,000 coins. This Pokémon gets along well with others and is quick to make friends with anybody.', 'evolutionChains': [[{ 'id': 999, 'name': 'Gimmighoul' }, { 'id': 1000, 'name': 'Gholdengo', 'condition': 'Gimmighoul Coins' }]] },
  1001: { 'id': 1001, 'height': 15, 'weight': 742, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/1001.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1001.png', 'abilities': ['Tablets Of Ruin'], 'stats': { 'hp': 85, 'attack': 85, 'defense': 100, 'special-attack': 95, 'special-defense': 135, 'speed': 70 }, 'flavorText': 'The grudge of a person punished for writing the king’s evil deeds upon wooden tablets has clad itself in dead leaves to become a Pokémon.', 'evolutionChains': [[{ 'id': 1001, 'name': 'Wo Chien' }]] },
  1002: { 'id': 1002, 'height': 19, 'weight': 1522, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/1002.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1002.png', 'abilities': ['Sword Of Ruin'], 'stats': { 'hp': 80, 'attack': 120, 'defense': 80, 'special-attack': 90, 'special-defense': 65, 'speed': 135 }, 'flavorText': 'This Pokémon can control 100 tons of fallen snow. It plays around innocently by leaping in and out of avalanches it has caused.', 'evolutionChains': [[{ 'id': 1002, 'name': 'Chien Pao' }]] },
  1003: { 'id': 1003, 'height': 27, 'weight': 6997, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/1003.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1003.png', 'abilities': ['Vessel Of Ruin'], 'stats': { 'hp': 155, 'attack': 110, 'defense': 125, 'special-attack': 55, 'special-defense': 80, 'speed': 45 }, 'flavorText': 'The fear poured into an ancient ritual vessel has clad itself in rocks and dirt to become a Pokémon.', 'evolutionChains': [[{ 'id': 1003, 'name': 'Ting Lu' }]] },
  1004: { 'id': 1004, 'height': 4, 'weight': 49, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/1004.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1004.png', 'abilities': ['Beads Of Ruin'], 'stats': { 'hp': 55, 'attack': 80, 'defense': 80, 'special-attack': 135, 'special-defense': 120, 'speed': 100 }, 'flavorText': 'It controls flames burning at over 5,400 degrees Fahrenheit. It casually swims through the sea of lava it creates by melting rock and sand.', 'evolutionChains': [[{ 'id': 1004, 'name': 'Chi Yu' }]] },
  1005: { 'id': 1005, 'height': 20, 'weight': 3800, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/1005.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1005.png', 'abilities': ['Protosynthesis'], 'stats': { 'hp': 105, 'attack': 139, 'defense': 71, 'special-attack': 55, 'special-defense': 101, 'speed': 119 }, 'flavorText': 'It is possible that this is the creature listed as Roaring Moon in an expedition journal that still holds many mysteries.', 'evolutionChains': [[{ 'id': 1005, 'name': 'Roaring Moon' }]] },
  1006: { 'id': 1006, 'height': 14, 'weight': 350, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/1006.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1006.png', 'abilities': ['Quark Drive'], 'stats': { 'hp': 74, 'attack': 130, 'defense': 90, 'special-attack': 120, 'special-defense': 60, 'speed': 116 }, 'flavorText': 'It has some similarities to a mad scientist’s invention covered in a paranormal magazine.', 'evolutionChains': [[{ 'id': 1006, 'name': 'Iron Valiant' }]] },
