  1011: { 'id': 1011, 'height': 4, 'weight': 97, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/1011.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1011.png', 'abilities': ['Supersweet Syrup', 'Gluttony', 'Sticky Hold'], 'stats': { 'hp': 80, 'attack': 80, 'defense': 110, 'special-attack': 95, 'special-defense': 80, 'speed': 40 }, 'flavorText': 'Dipplin is two creatures in one Pokémon. Its evolution was triggered by a special apple grown only in one place.', 'evolutionChains': [[{ 'id': 840, 'name': 'Applin' }, { 'id': 841, 'name': 'Flapple', 'condition': 'Use Tart Apple' }], [{ 'id': 840, 'name': 'Applin' }, { 'id': 842, 'name': 'Appletun', 'condition': 'Use Sweet Apple' }], [{ 'id': 840, 'name': 'Applin' }, { 'id': 1011, 'name': 'Dipplin', 'condition': 'Use Syrupy Apple' }, { 'id': 1019, 'name': 'Hydrapple', 'condition': 'Know Dragon Cheer' }]] },
  1012: { 'id': 1012, 'height': 1, 'weight': 11, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/1012.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1012.png', 'abilities': ['Hospitality', 'Heatproof'], 'stats': { 'hp': 40, 'attack': 45, 'defense': 45, 'special-attack': 74, 'special-defense': 54, 'speed': 50 }, 'flavorText': 'Supposedly, the regrets of a tea ceremony master who died before perfecting his craft lingered in some matcha and became a Pokémon.', 'evolutionChains': [[{ 'id': 1012, 'name': 'Poltchageist' }, { 'id': 1013, 'name': 'Sinistcha', 'condition': 'Use Unremarkable Teacup' }]] },
  1013: { 'id': 1013, 'height': 2, 'weight': 22, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/1013.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1013.png', 'abilities': ['Hospitality', 'Heatproof'], 'stats': { 'hp': 71, 'attack': 60, 'defense': 106, 'special-attack': 121, 'special-defense': 80, 'speed': 70 }, 'flavorText': 'It pretends to be tea, trying to fool people into drinking it so it can drain their life-force. Its ruse is generally unsuccessful.', 'evolutionChains': [[{ 'id': 1012, 'name': 'Poltchageist' }, { 'id': 1013, 'name': 'Sinistcha', 'condition': 'Use Unremarkable Teacup' }]] },
  1014: { 'id': 1014, 'height': 18, 'weight': 922, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/1014.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1014.png', 'abilities': ['Toxic Chain', 'Guard Dog'], 'stats': { 'hp': 88, 'attack': 128, 'defense': 115, 'special-attack': 58, 'special-defense': 86, 'speed': 80 }, 'flavorText': 'After all its muscles were stimulated by the toxic chain around its neck, Okidogi transformed and gained a powerful physique.', 'evolutionChains': [[{ 'id': 1014, 'name': 'Okidogi' }]] },
  1015: { 'id': 1015, 'height': 10, 'weight': 122, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/1015.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1015.png', 'abilities': ['Toxic Chain', 'Frisk'], 'stats': { 'hp': 88, 'attack': 75, 'defense': 66, 'special-attack': 130, 'special-defense': 90, 'speed': 106 }, 'flavorText': 'The chain is made from toxins that enhance capabilities. It stimulated Munkidori\'s brain and caused the Pokémon\'s psychic powers to bloom.', 'evolutionChains': [[{ 'id': 1015, 'name': 'Munkidori' }]] },
  1016: { 'id': 1016, 'height': 14, 'weight': 301, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/1016.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1016.png', 'abilities': ['Toxic Chain', 'Technician'], 'stats': { 'hp': 88, 'attack': 91, 'defense': 82, 'special-attack': 70, 'special-defense': 125, 'speed': 99 }, 'flavorText': 'Fezandipiti owes its beautiful looks and lovely voice to the toxic stimulants emanating from the chain wrapped around its body.', 'evolutionChains': [[{ 'id': 1016, 'name': 'Fezandipiti' }]] },
  1017: { 'id': 1017, 'height': 12, 'weight': 398, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/1017.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1017.png', 'abilities': ['Defiant'], 'stats': { 'hp': 80, 'attack': 120, 'defense': 84, 'special-attack': 60, 'special-defense': 96, 'speed': 110 }, 'flavorText': 'This Pokémon\'s type changes based on which mask it\'s wearing. It confounds its enemies with nimble movements and kicks.', 'evolutionChains': [[{ 'id': 1017, 'name': 'Ogerpon' }]] },
  1018: { 'id': 1018, 'height': 20, 'weight': 600, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/1018.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1018.png', 'abilities': ['Stamina', 'Sturdy', 'Stalwart'], 'stats': { 'hp': 90, 'attack': 105, 'defense': 130, 'special-attack': 125, 'special-defense': 65, 'speed': 85 }, 'flavorText': 'It gathers static electricity from its surroundings. The beams it launches when down on all fours are tremendously powerful.', 'evolutionChains': [[{ 'id': 884, 'name': 'Duraludon' }, { 'id': 1018, 'name': 'Archaludon', 'condition': 'Use Metal Alloy' }]] },
