  1021: { 'id': 1021, 'height': 52, 'weight': 4800, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/1021.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1021.png', 'abilities': ['Protosynthesis'], 'stats': { 'hp': 125, 'attack': 73, 'defense': 91, 'special-attack': 137, 'special-defense': 89, 'speed': 75 }, 'flavorText': 'It\'s said to incinerate everything around it with lightning launched from its fur. Very little is known about this creature.', 'evolutionChains': [[{ 'id': 1021, 'name': 'Raging Bolt' }]] },
