  1024: { 'id': 1024, 'height': 2, 'weight': 65, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/1024.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1024.png', 'abilities': ['Tera Shift'], 'stats': { 'hp': 90, 'attack': 65, 'defense': 85, 'special-attack': 65, 'special-defense': 85, 'speed': 60 }, 'flavorText': 'Terapagos protects itself using its power to transform energy into hard crystals. This Pokémon is the source of the Terastal phenomenon.', 'evolutionChains': [[{ 'id': 1024, 'name': 'Terapagos' }]] },
  1025: { 'id': 1025, 'height': 3, 'weight': 3, 'sprite': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/1025.png', 'artwork': 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1025.png', 'abilities': ['Poison Puppeteer'], 'stats': { 'hp': 88, 'attack': 88, 'defense': 160, 'special-attack': 88, 'special-defense': 88, 'speed': 88 }, 'flavorText': 'It feeds others toxic mochi that draw out desires and capabilities. Those who eat the mochi fall under Pecharunt’s control, chained to its will.', 'evolutionChains': [[{ 'id': 1025, 'name': 'Pecharunt' }]] },
